// Normalize review fields and generate review_id
const items = $input.all();
const normalized = [];

for (const item of items) {
  const json = item.json;

  // Generate unique review_id if not present
  const reviewId = json.review_id || `csv_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  normalized.push({
    json: {
      source: 'csv',
      product_id: json.product_id || null,
      product_name: (json.product_name || 'Unknown').trim(),
      review_id: reviewId,
      reviewer_name: json.reviewer_name || null,
      rating: parseFloat(json.rating) || 3,
      review_title: (json.review_title || '').trim(),
      review_text: (json.review_text || '').trim(),
      review_date: json.review_date || new Date().toISOString().split('T')[0],
      country: json.country || 'Unknown',
      language: json.language || 'en'
    }
  });
}

return normalized;

// Rule-Based NLP Enrichment Engine
// Copy from lib/nlp-engine.js

const TOPIC_KEYWORDS = {
  battery: ['battery', 'charge', 'charging', 'power', 'drain', 'dies', 'life'],
  performance: ['slow', 'fast', 'lag', 'speed', 'performance', 'quick', 'responsive', 'sluggish'],
  durability: ['broke', 'broken', 'sturdy', 'fragile', 'durable', 'quality', 'build', 'cheap', 'flimsy'],
  pricing: ['expensive', 'cheap', 'price', 'value', 'worth', 'cost', 'overpriced', 'affordable'],
  delivery: ['shipping', 'arrived', 'delayed', 'delivery', 'shipment', 'package', 'late', 'damaged box'],
  sound: ['audio', 'noise', 'volume', 'sound', 'bass', 'treble', 'speaker', 'quiet', 'loud'],
  support: ['customer service', 'support', 'help', 'response', 'contacted', 'reply', 'warranty'],
  setup: ['install', 'installation', 'configure', 'setup', 'easy', 'complicated', 'manual', 'instructions'],
  screen: ['display', 'screen', 'brightness', 'resolution', 'pixels', 'colors', 'touch'],
  compatibility: ['compatible', 'compatibility', 'works with', 'connect', 'sync', 'pair', 'pairing'],
  design: ['design', 'looks', 'aesthetic', 'style', 'appearance', 'color', 'size', 'weight'],
  ui: ['interface', 'ui', 'menu', 'navigation', 'controls', 'buttons', 'app']
};

const URGENCY_KEYWORDS = {
  high: ['fire', 'smoke', 'overheat', 'overheating', 'hazard', 'exploded', 'explosion', 'dangerous', 'safety', 'burn', 'burning', 'hot', 'melt', 'melted', 'injury', 'hurt'],
  medium: ['broken', 'broke', 'stopped working', 'dead', 'refund', 'return', 'defective', 'not working', "doesn't work", 'failed', 'unusable', 'malfunction']
};

const SENTIMENT_MODIFIERS = {
  positive: ['amazing', 'excellent', 'perfect', 'love', 'great', 'awesome', 'fantastic', 'wonderful', 'best', 'impressed', 'highly recommend', 'recommend', 'happy', 'satisfied', 'exceeded', 'superb', 'outstanding'],
  negative: ['terrible', 'horrible', 'worst', 'awful', 'hate', 'disappointed', 'disappointing', 'poor', 'bad', 'useless', 'waste', 'regret', 'never', 'avoid', "don't buy", 'garbage', 'junk', 'pathetic']
};

function detectSentiment(rating, text) {
  const lowerText = text.toLowerCase();
  let sentiment, baseScore;

  if (rating >= 4) {
    sentiment = 'positive';
    baseScore = rating === 5 ? 0.9 : 0.6;
  } else if (rating <= 2) {
    sentiment = 'negative';
    baseScore = rating === 1 ? -0.9 : -0.6;
  } else {
    sentiment = 'neutral';
    baseScore = 0.0;
  }

  let modifier = 0;
  const positiveMatches = SENTIMENT_MODIFIERS.positive.filter(kw => lowerText.includes(kw)).length;
  const negativeMatches = SENTIMENT_MODIFIERS.negative.filter(kw => lowerText.includes(kw)).length;
  modifier = (positiveMatches * 0.1) - (negativeMatches * 0.1);

  let sentimentScore = Math.max(-1.0, Math.min(1.0, baseScore + modifier));

  if (sentimentScore >= 0.3 && sentiment !== 'positive') sentiment = 'positive';
  else if (sentimentScore <= -0.3 && sentiment !== 'negative') sentiment = 'negative';
  else if (sentimentScore > -0.3 && sentimentScore < 0.3) sentiment = 'neutral';

  sentimentScore = Math.round(sentimentScore * 100) / 100;

  return { sentiment, sentiment_score: sentimentScore };
}

function detectTopics(text) {
  const lowerText = text.toLowerCase();
  const detectedTopics = new Set();

  for (const [topic, keywords] of Object.entries(TOPIC_KEYWORDS)) {
    for (const keyword of keywords) {
      if (lowerText.includes(keyword)) {
        detectedTopics.add(topic);
        break;
      }
    }
  }

  return detectedTopics.size === 0 ? ['other'] : Array.from(detectedTopics).slice(0, 6);
}

function classifyUrgency(text, rating) {
  const lowerText = text.toLowerCase();

  for (const keyword of URGENCY_KEYWORDS.high) {
    if (lowerText.includes(keyword)) return 'high';
  }

  for (const keyword of URGENCY_KEYWORDS.medium) {
    if (lowerText.includes(keyword)) return 'med';
  }

  if (rating === 1) return 'med';
  return 'low';
}

function extractKeyPhrases(text) {
  const phrases = [];
  const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);

  sentences.forEach(sentence => {
    const words = sentence.trim().toLowerCase().split(/\s+/);
    for (let i = 0; i < words.length - 1; i++) {
      const phrase = words.slice(i, Math.min(i + 3, words.length)).join(' ');
      const containsImportantWord = [
        ...Object.values(TOPIC_KEYWORDS).flat(),
        ...SENTIMENT_MODIFIERS.positive,
        ...SENTIMENT_MODIFIERS.negative
      ].some(keyword => phrase.includes(keyword));

      if (containsImportantWord && phrase.length > 5 && phrase.length < 50) {
        phrases.push(phrase);
      }
    }
  });

  return [...new Set(phrases)].slice(0, 5);
}

function generateSummary(rating, topics, urgency, sentiment) {
  const topicStr = topics.length > 0 ? topics.slice(0, 3).join(', ') : 'general';
  let summary = `Rating ${rating}/5. `;

  if (sentiment === 'positive') summary += 'Positive feedback ';
  else if (sentiment === 'negative') summary += 'Negative feedback ';
  else summary += 'Mixed feedback ';

  summary += `regarding: ${topicStr}. `;

  if (urgency === 'high') summary += 'HIGH URGENCY - Safety concern.';
  else if (urgency === 'med') summary += 'Medium urgency - Product issue reported.';
  else summary += 'Low urgency.';

  return summary;
}

function enrichReview(review) {
  const { rating = 3, review_text = '', review_title = '' } = review;
  const fullText = `${review_title} ${review_text}`.trim();

  if (!fullText || fullText.length < 3) {
    return {
      sentiment: 'neutral',
      sentiment_score: 0.0,
      topics: ['other'],
      urgency: 'low',
      summary: 'Review text too short for analysis.',
      key_phrases: [],
      ai_model: 'rule-based-v1',
      ai_raw_json: null
    };
  }

  const { sentiment, sentiment_score } = detectSentiment(rating, fullText);
  const topics = detectTopics(fullText);
  const urgency = classifyUrgency(fullText, rating);
  const key_phrases = extractKeyPhrases(fullText);
  const summary = generateSummary(rating, topics, urgency, sentiment);

  return {
    sentiment,
    sentiment_score,
    topics,
    urgency,
    summary,
    key_phrases,
    ai_model: 'rule-based-v1',
    ai_raw_json: null
  };
}

// Main execution
const items = $input.all();
const enrichedItems = [];

for (const item of items) {
  const review = item.json;
  const enrichment = enrichReview(review);

  enrichedItems.push({
    json: {
      ...review,
      ...enrichment
    }
  });
}

return enrichedItems;

// Success summary
const items = $input.all();
const count = items.length;

const sentimentCounts = items.reduce((acc, item) => {
  acc[item.json.sentiment] = (acc[item.json.sentiment] || 0) + 1;
  return acc;
}, {});

const highUrgencyCount = items.filter(item => item.json.urgency === 'high').length;

return [{
  json: {
    success: true,
    message: `Successfully processed ${count} reviews`,
    sentiment_breakdown: sentimentCounts,
    high_urgency_reviews: highUrgencyCount,
    timestamp: new Date().toISOString()
  }
}];
